            background-color: #6A8CFF;
            text-align: center;
            display: flex;
            justify-content: center;
            align-items: center;
            height: 100vh;
            margin: 0;
        }

        .container {
            width: 60%;
            background-color: #fff;
            padding: 30px;
            border-radius: 20px;
            box-shadow: 2px 2px 20px rgba(0, 0, 0, 0.1);
        }

        h2 {
            color: #333;
            font-size: 24px;
            margin-bottom: 30px;
        }

        .button-grid {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 12px;
        }

        .btn {
            display: flex;
            align-items: center;
            justify-content: center;
            padding: 30px;
            font-size: 20px;
            text-decoration: none;
            color: #333;
            border-radius: 10px;
            background-color: #f8f9fa;
            border: 1px solid #ddd;
            transition: background-color 0.3s, transform 0.2s;
        }

        .btn:hover {
            transform: translateY(-3px);
        }

        .btn img {
            margin-right: 10px;
            height: 24px;
        }

        /* Custom button colors */
        .deposit {
            background-color: #e6f7e6;
            color: #28a745;
        }

        .deposit:hover {
            background-color: #c3e6cb;
        }

        .withdraw {
            background-color: #e6f2ff;
            color: #007bff;
        }

        .withdraw:hover {
            background-color: #b8daff;
        }

        .fast-cash {
            background-color: #faf5ff;
            color: #6f42c1;
        }

        .fast-cash:hover {
            background-color: #dab6f7;
        }

        .change-pin {
            background-color: #fff7ed;
            color: #fd7e14;
        }

        .change-pin:hover {
            background-color: #ffd8b1;
        }

        .balance-enquiry {
            background-color: #e6f0ff;
            color: #6c757d;
        }

        .balance-enquiry:hover {
            background-color: #b8d2f7;
        }

        .cancel {
            background-color: #ffe6e6;
            color: #dc3545;
        }

        .cancel:hover {
            background-color: #f5c6cb;
        }

